import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';

const Product = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const { data } = await api.get(`/products/${id}`);
        setProduct(data);
      } catch (error) {
        console.error('Error fetching product', error);
        // Fallback data
        setProduct({
          _id: id,
          name: 'Signature Piece',
          price: 500,
          description: 'A masterpiece of modern tailoring. Crafted from premium materials for the ultimate luxury experience.',
          imageUrl: ''
        });
      } finally {
        setLoading(false);
      }
    };

    fetchProduct();
  }, [id]);

  const addToCart = () => {
    // Basic cart logic could be implemented here or via context
    alert('Added to cart');
    navigate('/cart');
  };

  if (loading) return <div className="container"><p>Loading...</p></div>;

  return (
    <div className="container">
      <div className="product-details-container">
        <div className="product-details-image" style={{ backgroundImage: `url(${product.imageUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' }}></div>
        <div className="product-details-info">
          <h1 className="product-details-title">{product.name}</h1>
          <p className="product-details-price">${product.price}</p>
          <p className="product-details-description">{product.description}</p>
          <button className="btn" onClick={addToCart}>Add to Cart</button>
        </div>
      </div>
    </div>
  );
};

export default Product;
